template.template_md:
{% block content %}
<style>
  @media print {
    .timeline-bar {
      page-break-inside: avoid;
    }
    /* Print: disable sticky so thead repeats cleanly */
    table.vt > thead { position: static !important; }
    .filter-controls { display: none !important; } /* Hide filter controls when printing */
  }

  .timeline-container {
    margin-top: 40px;
    padding-right: 20px;
  }

  .timeline-row {
    margin-bottom: 10px;
  }

  .timeline-bar {
    position: relative;
    height: 16px;
    background-color: green;
    width: 100%;
  }

  .timeline-block {
    box-sizing: border-box;
    position: absolute;
    height: 100%;
    background-color: red;
    border: 1px solid #000;
  }

  .timeline-label {
    font-size: 11px;
    margin-bottom: 4px;
  }

  /* --- New styles for dropdowns and filtering (from Computer Inventory Report) --- */
  :root {
    --border-color: #ddd;
    --pane-gap: 10px;
    --focus: #3b82f6;
  }

  .filter-controls {
    display: flex;
    gap: 10px;
    margin-top: 15px;
    margin-bottom: 20px;
    align-items: center;
    flex-wrap: wrap;
  }

  /* Popover (picker) */
  .popover {
    position: fixed; min-width: 260px; max-width: 380px; max-height: 280px; overflow: auto;
    background: #fff; border: 1px solid #ddd; border-radius: 8px;
    box-shadow: 0 8px 24px rgba(0,0,0,.12); padding: 8px; z-index: 10000;
  }
  .opt { display: flex; align-items: center; gap: 8px; padding: 4px 2px; }
  .opt label { flex: 1 1 auto; font-size: 12px; }

  /* Unified combo for column pickers (unchanged) */
  .combo{
    position: relative; /* For clear button positioning */
    display:flex; align-items:center; gap:6px;
    border:1px solid #ddd; border-radius:8px; background:#fff;
    padding:2px 8px;
    min-width: 200px; /* Adjust as needed */
  }
  .combo:focus-within{ border-color: var(--focus); box-shadow: 0 0 0 2px rgba(59,130,246,.12); }
  .combo-input{ flex:1 1 auto; border:0; outline:0; font-size:12px; padding:6px 6px; background:transparent; }
  .combo-right{ display:flex; align-items:center; gap:6px; }
  .combo-btn{
    display:inline-flex; align-items:center; gap:4px;
    border:0; background:transparent; cursor:pointer; padding:4px; border-radius:6px;
  }
  .combo-btn:hover{ background:#f1f5f9; }
  .chev{ width:14px; height:14px; opacity:.7; }
  .badge{
    font-size:11px; padding:2px 6px; border-radius:999px;
    background:#eef2ff; color:#3730a3; border:1px solid #c7d2fe;
  }

  /* New Clear Button Styling */
  .clear-filter-btn {
    position: absolute;
    top: 0;
    right: 0;
    transform: translate(50%, -50%);
    width: 18px;
    height: 18px;
    border-radius: 50%;
    background: #e53e3e;
    color: white;
    border: none;
    cursor: pointer;
    display: none; /* JS will toggle to 'flex' */
    align-items: center;
    justify-content: center;
    font-family: sans-serif;
    font-size: 13px;
    font-weight: bold;
    line-height: 18px;
    padding: 0;
    z-index: 5;
  }
  .clear-filter-btn:hover { background: #c53030; }
  .combo .clear-filter-btn { right: 0px; } /* Position for combo boxes with dropdown arrow */

  /* Table styling for downtime list */
  .report-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 20px;
  }
  .report-table thead th {
    background: #f8f8f8;
    border-bottom: 2px solid #ddd;
    padding: 8px;
    text-align: left;
  }
  .report-table tbody td {
    border-bottom: 1px solid #eee;
    padding: 8px;
  }
  .report-table tbody tr:hover {
    background-color: #f5f5f5;
  }
  #loading-data {
    display:flex; justify-content:center; align-items:center; height:100px;
    font-size:14px; font-weight:bold; color:#555;
  }
</style>

<div class="report-header">
  <img src="https://github.com/amidaware/reporting-templates/blob/master/assets/gbtnavy%20(256).png?raw=true"
       alt="Logo"
       class="header-logo small-logo">
  <div class="header-date">
    <h1>Agent Uptime Report</h1>
    <h2>Report Date: {{ report_run_timestamp.strftime('%Y-%m-%d') }}</h2>
  </div>
</div>

<div class="filter-controls">
    <label style="font-weight: bold; margin-right: 5px;">Filter By:</label>
    <div id="clientFilterCombo"></div>
    <div id="siteFilterCombo"></div>
    <div class="row-count" aria-live="polite" style="font-size:13px; margin-left: 10px;">
        Filtered Downtime Records: <strong><span id="visibleDowntimeCount">0</span></strong>
        of <span id="totalDowntimeCount">0</span>
    </div>
</div>

{% set cutoff = timedelta_30_days %}
{% set alert_events_full = [] %}
{% for item in data_sources.allFieldsAlerts %}
  {% if item.alert_type == "availability"
        and item.resolved
        and item.alert_time is defined
        and item.resolved_on is defined
        and item.agent__hostname is defined
        and item.alert_time >= cutoff %}
    {% set downtime = (item.resolved_on - item.alert_time).total_seconds() / 60 %}
    {% set _ = alert_events_full.append({
      "agent": item.agent__hostname,
      "start": item.alert_time.isoformat(),
      "end":   item.resolved_on.isoformat(),
      "message": item.message,
      "downtime_minutes": downtime,
      "alert_time_fmt": item.alert_time.strftime('%Y-%m-%d %H:%M'),
      "resolved_on_fmt": item.resolved_on.strftime('%Y-%m-%d %H:%M'),
      "clientRaw": (item.agent__site__client__name or (client.name if client and client.name else 'N/A')),
      "site": (item.agent__site__name or 'N/A')
    }) %}
  {% endif %}
{% endfor %}

<div class="section timeline-container" id="timelineChart">
  <h2>Agent Timeline (Green = Online, Red = Offline)</h2>
  <div id="loading-timeline" style="display:none;" class="row-count">Loading timeline...</div>
</div>

<h2>Downtime List</h2>
<div id="loading-data" style="display: none;">Loading downtime data...</div>
<table class="report-table">
  <thead>
    <tr>
      <th>Agent ID</th>
      <th>Client</th>
      <th>Site</th>
      <th>Message</th>
      <th>Time Off</th>
      <th>Time On</th>
      <th>Downtime</th>
    </tr>
  </thead>
  <tbody id="downtimeTableBody">
    <!-- Downtime list will be rendered by JavaScript -->
  </tbody>
</table>

<script id="uptime-alerts-json" type="application/json">
  {{ alert_events_full | tojson | safe }}
</script>

<script>
  // Utility functions (from Computer Inventory Report)
  var $=function(s,r){return(r||document).querySelector(s);};
  var $$=function(s,r){return Array.prototype.slice.call((r||document).querySelectorAll(s));};
  var debounce=function(fn,ms){var t;return function(){var a=arguments;clearTimeout(t);t=setTimeout(function(){fn.apply(null,a);},ms||200);};};
  var htmlNode=function(s){var el=document.createElement('span');el.innerHTML=String(s||'');return el;};
  var stripHtml=function(s){var d=document.createElement('div');d.innerHTML=String(s||'');return d.textContent||d.innerText||'';};

  // Global data from Jinja2
  const allAlertsData = JSON.parse(document.getElementById('uptime-alerts-json').textContent || '[]');

  // Initial state for filters
  var state = {
    clientSite: { textClient: '', textSite: '', selClient: [], selSite: [] },
  };

  function getFilteredAlerts() {
    return allAlertsData.filter(item => {
      // Client filter
      if (state.clientSite.selClient.length > 0) {
        if (state.clientSite.selClient.indexOf(item.clientRaw) === -1) return false;
      } else if (state.clientSite.textClient) {
        if (item.clientRaw.toLowerCase().indexOf(state.clientSite.textClient.toLowerCase()) === -1) return false;
      }

      // Site filter
      if (state.clientSite.selSite.length > 0) {
        if (state.clientSite.selSite.indexOf(item.site) === -1) return false;
      } else if (state.clientSite.textSite) {
        if (item.site.toLowerCase().indexOf(state.clientSite.textSite.toLowerCase()) === -1) return false;
      }
      return true;
    });
  }

  function uniqueValuesByKey(key, list){
    var m=new Map();
    for(var i=0;i<list.length;i++){
      var val=String(list[i][key]||'N/A');
      m.set(val,(m.get(val)||0)+1);
    }
    var arr=Array.from(m.entries()).map(function(x){return {v:x[0], c:x[1]};});
    arr.sort(function(a,b){return a.v.localeCompare(b.v,undefined,{numeric:true,sensitivity:'base'});});
    return arr;
  }

  function filteredAlertsExcluding(kind){
    var savedClientSite = JSON.parse(JSON.stringify(state.clientSite));
    if(kind === 'client') state.clientSite.selClient = []; state.clientSite.textClient = '';
    if(kind === 'site')   state.clientSite.selSite = [];   state.clientSite.textSite = '';
    var rows = allAlertsData.filter(item => {
      // Client filter
      if (state.clientSite.selClient.length > 0) {
        if (state.clientSite.selClient.indexOf(item.clientRaw) === -1) return false;
      } else if (state.clientSite.textClient) {
        if (item.clientRaw.toLowerCase().indexOf(state.clientSite.textClient.toLowerCase()) === -1) return false;
      }

      // Site filter
      if (state.clientSite.selSite.length > 0) {
        if (state.clientSite.selSite.indexOf(item.site) === -1) return false;
      } else if (state.clientSite.textSite) {
        if (item.site.toLowerCase().indexOf(state.clientSite.textSite.toLowerCase()) === -1) return false;
      }
      return true;
    });
    state.clientSite = savedClientSite; // Restore original state
    return rows;
  }

  // --- Popover and Combo Box functions (adapted from Computer Inventory Report) ---
  function buildCombo(opts){
    var box=document.createElement('div'); box.className='combo';
    var input=document.createElement('input');
    input.className='combo-input';
    input.placeholder=opts.placeholder||'Search';
    input.value = opts.getText();

    var right=document.createElement('div'); right.className='combo-right';
    var badge=document.createElement('span');
    badge.className='badge';
    var count = opts.getCount();
    badge.textContent = count > 0 ? String(count)+' selected' : 'Pick';
    if(count === 0) badge.style.display = 'none';

    var btn=document.createElement('button'); btn.type='button'; btn.className='combo-btn';
    btn.setAttribute('aria-label','Pick values');
    btn.innerHTML = '<svg class="chev" viewBox="0 0 24 24" aria-hidden="true"><path d="M7 10l5 5 5-5z"/></svg>';
    btn.addEventListener('click', function(e){ e.stopPropagation(); opts.open(btn); });

    var clearBtn = document.createElement('button');
    clearBtn.className = 'clear-filter-btn';
    clearBtn.innerHTML = '&times;';
    clearBtn.setAttribute('aria-label', 'Clear filter for ' + opts.title);

    var toggleClearBtn = function() {
      var hasText = input.value.trim() !== '';
      var hasSelection = opts.getCount() > 0;
      clearBtn.style.display = (hasText || hasSelection) ? 'flex' : 'none';
    };

    clearBtn.addEventListener('click', function() {
      input.value = '';
      opts.clear();
      box._updateBadge(0);
      renderReport(); // Re-render everything
    });

    input.addEventListener('input', debounce(function(e){
      opts.setText(e.target.value||'');
      toggleClearBtn();
      renderReport(); // Re-render everything
    }, 120));

    box._updateBadge = function(n){
      if(n>0){ badge.style.display='inline-block'; badge.textContent = n+' selected'; }
      else { badge.style.display='none'; }
      toggleClearBtn();
    };

    right.appendChild(badge);
    right.appendChild(btn);
    box.appendChild(input);
    box.appendChild(clearBtn);
    box.appendChild(right);
    toggleClearBtn();
    return box;
  }

  var _popoverEl = null; // Private state for current popover

  function placePopoverUnder(anchorBtn, pop){
    var rect = anchorBtn.getBoundingClientRect();
    var left = rect.left;
    var top  = rect.bottom + 6;

    document.body.appendChild(pop);
    var pw = pop.offsetWidth, ph = pop.offsetHeight;

    // Adjust position if it goes off screen
    if (left + pw > window.innerWidth - 8) left = Math.max(8, window.innerWidth - pw - 8);
    if (top  + ph > window.innerHeight - 8) {
      var altTop = rect.top - ph - 6;
      top = (altTop >= 8) ? altTop : Math.max(8, window.innerHeight - ph - 8);
    }

    pop.style.left = left + 'px';
    pop.style.top  = top  + 'px';
  }

  function togglePopoverDual(kind, anchorBtn){
    closePopover();
    anchorBtn.classList.add('active');

    var pop=document.createElement('div'); pop.className='popover';
    var list=document.createElement('div'); pop.appendChild(list);
    var baseRows=filteredAlertsExcluding(kind);

    function renderList(){
      list.innerHTML='';
      var items=uniqueValuesByKey(kind==='client'?'clientRaw':'site', baseRows);
      var selArr = (kind==='client' ? (state.clientSite.selClient||[]) : (state.clientSite.selSite||[]));

      items.forEach(function(it){
        var row=document.createElement('div'); row.className='opt';
        var cb=document.createElement('input'); cb.type='checkbox'; cb.value=it.v; cb.checked = selArr.indexOf(it.v)>-1;
        var lab=document.createElement('label'); lab.textContent=it.v+' ('+it.c+')';

        cb.addEventListener('change', function(e){
          var arr = (kind==='client' ? state.clientSite.selClient : state.clientSite.selSite);
          var v = e.target.value;
          if(e.target.checked){ if(arr.indexOf(v)===-1) arr.push(v); }
          else { var idx=arr.indexOf(v); if(idx>-1) arr.splice(idx,1); }

          renderReport(); // Re-render everything
          var combo = anchorBtn.closest('.combo');
          if (combo && combo._updateBadge) combo._updateBadge(arr.length);
        });

        row.appendChild(cb); row.appendChild(lab); list.appendChild(row);
      });
    }
    renderList();

    placePopoverUnder(anchorBtn, pop);

    function closeOnOutside(e){ if(!pop.contains(e.target) && e.target!==anchorBtn){ closePopover(); } }
    document.addEventListener('mousedown', closeOnOutside);
    pop._closeHandler=closeOnOutside; pop._anchor=anchorBtn; _popoverEl=pop;
  }

  function closePopover(){
    var pop=_popoverEl;
    if(pop){
      document.removeEventListener('mousedown', pop._closeHandler||function(){});
      if(pop._anchor) pop._anchor.classList.remove('active');
      pop.remove();
      _popoverEl=null;
    }
  }

  // --- Downtime Table Rendering ---
  function renderDowntimeTable(data) {
    const tbody = document.getElementById('downtimeTableBody');
    tbody.innerHTML = '';
    const visibleCountSpan = document.getElementById('visibleDowntimeCount');

    if (data.length === 0) {
      document.getElementById('loading-data').style.display = 'none';
      const noDataRow = document.createElement('tr');
      noDataRow.innerHTML = '<td colspan="7" style="text-align: center; padding: 20px;">No downtime records found for the selected filters.</td>';
      tbody.appendChild(noDataRow);
      visibleCountSpan.textContent = '0';
      return;
    }

    data.forEach(item => {
      const tr = document.createElement('tr');

      // Calculate downtime duration
      const totalMins = Math.round(item.downtime_minutes);
      const days = Math.floor(totalMins / 1440);
      const hrs = Math.floor((totalMins % 1440) / 60);
      const min = totalMins % 60;

      let downtimeDisplay = '';
      if (days > 0) downtimeDisplay += `${days}d `;
      if (hrs > 0) downtimeDisplay += `${hrs}h `;
      if (min > 0 || (days === 0 && hrs === 0)) downtimeDisplay += `${min}m`;

      tr.innerHTML = `
        <td>${item.agent}</td>
        <td>${item.clientRaw}</td>
        <td>${item.site}</td>
        <td>${item.message}</td>
        <td>${item.alert_time_fmt}</td>
        <td>${item.resolved_on_fmt}</td>
        <td>${downtimeDisplay.trim()}</td>
      `;
      tbody.appendChild(tr);
    });
    document.getElementById('loading-data').style.display = 'none';
    visibleCountSpan.textContent = data.length;
  }


  // --- Timeline Rendering ---
  function renderTimelineChart(events) {
    const container = document.getElementById("timelineChart");
    container.style.margin = "0 20px";
    document.getElementById('loading-timeline').style.display = 'block';

    // Clear previous timeline content, except the main title
    const existingContent = container.querySelectorAll('.timeline-row, p, img');
    existingContent.forEach(node => node.remove());

    if (!events.length) {
      const p = document.createElement("p");
      p.textContent = "No downtime data found for the selected filters.";
      container.appendChild(p);
      document.getElementById('loading-timeline').style.display = 'none';
      return;
    }

    const minTime = Math.min(...events.map(e => new Date(e.start).getTime()));
    const maxTime = Math.max(...events.map(e => new Date(e.end).getTime()));
    const range   = maxTime - minTime;

    const grouped = {};
    events.forEach(e => {
      if (!grouped[e.agent]) grouped[e.agent] = { events: [], totalDowntime: 0 };
      const start   = new Date(e.start);
      const end     = new Date(e.end);
      const minutes = (end - start) / 60000;
      grouped[e.agent].events.push({ start, end });
      grouped[e.agent].totalDowntime += minutes;
    });

    Object.entries(grouped).forEach(([agent, data]) => {
      const totalMins = Math.round(data.totalDowntime);
      const days      = Math.floor(totalMins / 1440);
      const hrs       = Math.floor((totalMins % 1440) / 60);
      const min       = totalMins % 60;
      const summary   = `(Offline ${days} day${days !== 1 ? 's' : ''} ` +
                        `${hrs} hr${hrs !== 1 ? 's' : ''} ${min} min in last 30 days)`;

      const row  = document.createElement("div");
      row.className = "timeline-row";
      row.style.marginBottom = "30px";

      const label = document.createElement("div");
      label.className = "timeline-label";
      label.innerHTML = `<strong>${agent}</strong> ${summary}`;
      row.appendChild(label);

      const barWrapper = document.createElement("div");
      barWrapper.style.position = "relative";

      const bar = document.createElement("div");
      bar.className = "timeline-bar";
      bar.style.marginBottom = "4px";

      data.events.forEach(({ start, end }) => {
        const offset = ((start.getTime() - minTime) / range) * 100;
        const width  = ((end.getTime() - start.getTime()) / range) * 100;

        const block = document.createElement("div");
        block.className = "timeline-block";
        block.style.left  = offset + "%";
        block.style.width = width  + "%";
        block.title = `${start.toLocaleString()} – ${end.toLocaleString()}`;
        bar.appendChild(block);
      });

      const tickRow = document.createElement("div");
      tickRow.style.borderTop = "1px solid #ccc";
      tickRow.style.position  = "relative";
      tickRow.style.height    = "16px";

      const totalDays = Math.ceil(range / (1000 * 60 * 60 * 24));
      // Ensure totalDays is at least 1 to prevent division by zero for very short ranges
      const actualTotalDays = Math.max(1, totalDays);

      for (let i = 0; i <= actualTotalDays; i++) {
        const tick = document.createElement("div");
        tick.style.position = "absolute";
        tick.style.left     = ((i / actualTotalDays) * 100) + "%";
        tick.style.height   = "100%";
        tick.style.borderLeft = "1px dashed #888";
        tick.style.fontSize   = "9px";
        tick.style.color      = "#333";
        tick.style.paddingLeft = "2px";
        tick.style.whiteSpace  = "nowrap";

        const dayDate = new Date(minTime + i * 24 * 60 * 60 * 1000);
        tick.textContent = dayDate.toLocaleDateString(undefined, {
          weekday: 'short', day: 'numeric'
        });

        tickRow.appendChild(tick);
      }

      barWrapper.appendChild(bar);
      barWrapper.appendChild(tickRow);
      row.appendChild(barWrapper);
      container.appendChild(row);
    });

    document.getElementById('loading-timeline').style.display = 'none';

    // HTML2Canvas for print-friendly snapshot
    setTimeout(() => {
      window.html2canvas = window.html2canvas || window["html2canvas"];
      if (typeof html2canvas === "function") {
        html2canvas(container).then(canvas => {
          const img = document.createElement("img");
          img.src = canvas.toDataURL("image/png");
          img.style.maxWidth = "100%";
          img.alt = "Agent Timeline Snapshot";
          // Clear container but keep the H2 title
          const h2Title = container.querySelector('h2');
          container.innerHTML = ''; // Clear everything
          container.appendChild(h2Title); // Re-add title
          container.appendChild(img);
        }).catch(err => console.error("html2canvas failed:", err));
      } else {
        console.warn("html2canvas not loaded.");
      }
    }, 500); // Increased timeout slightly
  }

  // --- Main Render Function ---
  function renderReport() {
    document.getElementById('loading-data').style.display = 'block';
    document.getElementById('loading-timeline').style.display = 'block';

    const filteredData = getFilteredAlerts();
    document.getElementById('totalDowntimeCount').textContent = allAlertsData.length;
    renderDowntimeTable(filteredData);
    renderTimelineChart(filteredData);
  }

  // --- Initialize Filters and Report ---
  document.addEventListener("DOMContentLoaded", function () {
    // Build Client Filter Combo
    document.getElementById('clientFilterCombo').appendChild(buildCombo({
      title: 'Client',
      placeholder: 'Search client',
      getText: () => state.clientSite.textClient || '',
      setText: (v) => { state.clientSite.textClient = v || ''; },
      getCount: () => (state.clientSite.selClient || []).length,
      open: (btn) => togglePopoverDual('client', btn),
      clear: () => { state.clientSite.textClient = ''; state.clientSite.selClient = []; }
    }));

    // Build Site Filter Combo
    document.getElementById('siteFilterCombo').appendChild(buildCombo({
      title: 'Site',
      placeholder: 'Search site',
      getText: () => state.clientSite.textSite || '',
      setText: (v) => { state.clientSite.textSite = v || ''; },
      getCount: () => (state.clientSite.selSite || []).length,
      open: (btn) => togglePopoverDual('site', btn),
      clear: () => { state.clientSite.textSite = ''; state.clientSite.selSite = []; }
    }));

    renderReport(); // Initial render of the report
  });
</script>
{% endblock %}
